class Solution {
    public int reverseDegree(String s) {
        int degree = 0;
        for (int i = 0; i < s.length(); i++) {
            char c = s.charAt(i);
            int posInAlphabet = c - 'a' + 1; // position in normal alphabet
            int posInReversedAlphabet = 26 - posInAlphabet + 1; // position in reversed alphabet
            degree += posInReversedAlphabet * (i + 1); // add product to degree
        }
        return degree;
    }
}
